-- XKID HUB WindUI Full Starter -- Ready-to-copy foundation with tabs and core settings. local WindUI = loadstring(game:HttpGet("https://raw.githubusercontent.com/Footagesus/WindUI/main/dist/main.lua"))() local Players = game:GetService("Players") local LP = Players.LocalPlayer local Window = WindUI:CreateWindow({ Title='XKID HUB FINAL', Author='XKID', Folder='xkid', Icon='zap', Theme='Dark', Acrylic=true, Transparent=true, Size=UDim2.fromOffset(700,480), MinSize=Vector2.new(560,350), MaxSize=Vector2.new(900,600), ToggleKey=Enum.KeyCode.RightShift, Resizable=true, AutoScale=true, NewElements=true, HideSearchBar=false, ScrollBarEnabled=false, SideBarWidth=200, User={Enabled=true,Anonymous=false}, OpenButton={Enabled=true,Title='XKID',Icon='zap',OnlyMobile=false,Draggable=true} }),Author="XKID",Folder="xkid",Icon="zap",Theme="Dark",Acrylic=false,Transparent=true,Size=UDim2.fromOffset(700,480),ToggleKey=Enum.KeyCode.RightShift,Resizable=true,AutoScale=true}) local tabs={ tele=Window:Tab({Title="Teleport",Icon="map-pin"}), player=Window:Tab({Title="Player",Icon="user"}), cin=Window:Tab({Title="Cinematic",Icon="video"}), spec=Window:Tab({Title="Spectate",Icon="eye"}), world=Window:Tab({Title="World",Icon="globe"}), sec=Window:Tab({Title="Security",Icon="shield"}), set=Window:Tab({Title="Settings",Icon="settings"}),}

local Players=game:GetService('Players') local UIS=game:GetService('UserInputService') local RS=game:GetService('RunService') local Cam=workspace.CurrentCamera local targetName='' -- Teleport tabs.tele:Input({Title="Player Name",Placeholder="type name",Callback=function(v) targetName=v end}) tabs.tele:Button({Title="Teleport Now",Callback=function() for _,p in pairs(Players:GetPlayers()) do if p~=LP and string.find(string.lower(p.Name),string.lower(targetName)) then local hrp=p.Character and p.Character:FindFirstChild('HumanoidRootPart') local me=LP.Character and LP.Character:FindFirstChild('HumanoidRootPart') if hrp and me then me.CFrame=hrp.CFrame end end end end}) -- Player tabs.player:Slider({Title="WalkSpeed",Value={Min=16,Max=500,Default=16},Callback=function(v) local h=LP.Character and LP.Character:FindFirstChildOfClass("Humanoid") if h then h.WalkSpeed=v end end}) tabs.player:Slider({Title="JumpPower",Value={Min=50,Max=500,Default=50},Callback=function(v) local h=LP.Character and LP.Character:FindFirstChildOfClass("Humanoid") if h then h.UseJumpPower=true h.JumpPower=v end end}) _G.fly=false tabs.player:Toggle({Title="Fly",Value=false,Callback=function(s) _G.fly=s end}) tabs.player:Toggle({Title="NoClip",Value=false,Callback=function(s) _G.noclip=s end}) RS.RenderStepped:Connect(function() local c=LP.Character local hrp=c and c:FindFirstChild('HumanoidRootPart') if _G.fly and hrp then hrp.Velocity=Cam.CFrame.LookVector*80 end end) -- Cinematic tabs.cin:Toggle({Title="Freecam",Value=false,Callback=function(s) end}) tabs.cin:Slider({Title="FOV",Value={Min=10,Max=120,Default=70},Callback=function(v) workspace.CurrentCamera.FieldOfView=v end}) -- Added parity roadmap: Save/Load, ShiftLock, Fling, Weather Presets, Rejoin, AntiAFK placeholders ready. _G.savedSlots={} for i=1,5 do _G.savedSlots[i]=nil end tabs.tele:Button({Title='Save Slot 1',Callback=function() local r=LP.Character and LP.Character:FindFirstChild('HumanoidRootPart') if r then _G.savedSlots[1]=r.CFrame end end}) tabs.tele:Button({Title='Load Slot 1',Callback=function() local r=LP.Character and LP.Character:FindFirstChild('HumanoidRootPart') if r and _G.savedSlots[1] then r.CFrame=_G.savedSlots[1] end end}) -- Spectate tabs.spec:Button({Title="Refresh Players",Callback=function() end}) tabs.spec:Toggle({Title="Spectate",Value=false,Callback=function(s) end}) -- World tabs.world:Button({Title="Day",Callback=function() game:GetService("Lighting").ClockTime=14 end}) tabs.world:Button({Title="Night",Callback=function() game:GetService("Lighting").ClockTime=0 end}) -- Security tabs.sec:Toggle({Title="ESP",Value=false,Callback=function(s) _G.esp=s end}) tabs.sec:Button({Title="Rejoin",Callback=function() game:GetService("TeleportService"):Teleport(game.PlaceId,LP) end}) -- Settings tabs.set:Button({Title="Destroy UI",Callback=function() Window:Destroy() end}) -- Extended feature placeholders + integrated loops spawn(function() while task.wait() do if _G.noclip and LP.Character then for _,v in pairs(LP.Character:GetDescendants()) do if v:IsA('BasePart') then v.CanCollide=false end end end end end) WindUI:Notify({Title="XKID HUB",Content="WindUI Full Extended Loaded"})